import { User } from "../../domain/entities/user";
import { IPasswordHasher } from "../../domain/services/ipassword-hasher";
import { EmailAlreadyExistsError } from "../../domain/errors/email-already-exist";
import { Email } from "../../domain/value-objects/email";
import { Password } from "../../domain/value-objects/password";
import { ILoginRepository, IRegisterRepository, ReturnedDBUser } from "@global-genius/database";
import { CreateUserInput } from "@global-genius/database/src/repositories/types/create-user";

export class RegisterUserUseCase {
  constructor(
    private loginRepo: ILoginRepository,
    private registerRepo: IRegisterRepository,
    private hasher: IPasswordHasher,
  ) {}

  async execute(input: CreateUserInput):Promise<ReturnedDBUser> {
    const existing = await this.loginRepo.findByEmail(input.email);

    if (existing) {
      throw new EmailAlreadyExistsError();
    }

    const email = Email.create(input.email).value;
    const password = Password.create(input.password).value;
    const hashedPassword = await this.hashPassword(password);
    const user = User.create({
      email,
      password: hashedPassword,
    });

   const dbUser = await this.registerRepo.create(user);

   return User.toJSON(dbUser)
  }

  private async hashPassword(password: string): Promise<string> {
    return await this.hasher.hash(password);
  }
}
